mapper.select:
SELECT *
FROM chapter_ratings
WHERE user_id = #{userId}
AND book_id = #{bookId}
AND chapter_number = #{chapterNumber}

SELECT AVG(rating) AS average_rating,
COUNT(*) AS total_ratings
FROM chapter_ratings
WHERE book_id = #{bookId}
AND chapter_number = #{chapterNumber}

SELECT rating,
COUNT(*) AS count
FROM chapter_ratings
WHERE book_id = #{bookId}
AND chapter_number = #{chapterNumber}
GROUP BY rating

mapper.delete:
DELETE FROM chapter_ratings
WHERE user_id = #{userId}
AND book_id = #{bookId}
AND chapter_number = #{chapterNumber}

mapper.select:
SELECT *
FROM chapter_ratings
WHERE user_id = #{userId}
AND book_id = #{bookId}
